package kotlinx.datetime.test.format

import kotlinx.datetime.*
import kotlinx.datetime.format.*
import kotlin.test.*

/**
 * Tests that error messages from the formatting API use user-friendly field names
 * instead of internal implementation names.
 */
class FormatErrorMessagesTest {

    @Test
    fun testOffsetHoursErrorMessage() {
        val format = DateTimeComponents.Format {
            offsetHours()
        }
        val exception = assertFailsWith<IllegalStateException> {
            format.format {
                // Not setting offset - should trigger error
            }
        }
        assertTrue(
            exception.message?.contains("offsetHours") == true,
            "Error message should mention 'offsetHours', but was: ${exception.message}"
        )
        assertFalse(
            exception.message?.contains("totalHoursAbs") == true,
            "Error message should NOT mention internal name 'totalHoursAbs', but was: ${exception.message}"
        )
    }

    @Test
    fun testOffsetMinutesOfHourErrorMessage() {
        val format = DateTimeComponents.Format {
            offsetHours()
            char(':')
            offsetMinutesOfHour()
        }
        val exception = assertFailsWith<IllegalStateException> {
            format.format {
                // Not setting offset - should trigger error for offsetHours first
            }
        }
        assertTrue(
            exception.message?.contains("offsetHours") == true,
            "Error message should mention 'offsetHours', but was: ${exception.message}"
        )
    }

    @Test
    fun testDayOfWeekErrorMessage() {
        val format = DateTimeComponents.Format {
            dayOfWeek(DayOfWeekNames.ENGLISH_FULL)
        }
        val exception = assertFailsWith<IllegalStateException> {
            format.format {
                // Not setting dayOfWeek - should trigger error
            }
        }
        assertTrue(
            exception.message?.contains("dayOfWeek") == true,
            "Error message should mention 'dayOfWeek', but was: ${exception.message}"
        )
        assertFalse(
            exception.message?.contains("isoDayOfWeek") == true,
            "Error message should NOT mention internal name 'isoDayOfWeek', but was: ${exception.message}"
        )
    }

    @Test
    fun testFormatWithSetOffsetWorks() {
        val format = DateTimeComponents.Format {
            offsetHours()
            char(':')
            offsetMinutesOfHour()
        }
        // Should not throw when offset is properly set
        val result = format.format {
            setOffset(UtcOffset(hours = 3, minutes = 30))
        }
        assertEquals("+03:30", result)
    }

    @Test
    fun testComplexFormatWithMissingOffset() {
        // This is the format from the issue report
        val readableFormat = DateTimeComponents.Format {
            year()
            char('-')
            monthNumber()
            char('-')
            dayOfMonth()
            char(' ')
            hour()
            char(':')
            minute()
            char(':')
            second()
            alternativeParsing({}) {
                char(' ')
            }
            alternativeParsing(
                { timeZoneId() },
                { offset(UtcOffset.Formats.ISO) }
            ) {
                offsetHours()
                char(':')
                offsetMinutesOfHour()
                optional {
                    char(':')
                    offsetSecondsOfMinute()
                }
            }
        }

        val zone = TimeZone.of("Europe/Berlin")
        val instant = Instant.parse("2023-06-15T10:30:00Z")

        // When the offset is not set, we should get a user-friendly error message
        val exception = assertFailsWith<IllegalStateException> {
            readableFormat.format {
                setDateTime(instant.toLocalDateTime(zone))
                timeZoneId = zone.id
                // Missing: setOffset(...)
            }
        }

        // The error message should mention the user-friendly field name
        assertTrue(
            exception.message?.contains("offsetHours") == true,
            "Error message should mention 'offsetHours', but was: ${exception.message}"
        )
        assertFalse(
            exception.message?.contains("totalHoursAbs") == true,
            "Error message should NOT mention internal name 'totalHoursAbs', but was: ${exception.message}"
        )
    }

    @Test
    fun testComplexFormatWorksWhenOffsetIsSet() {
        val readableFormat = DateTimeComponents.Format {
            year()
            char('-')
            monthNumber()
            char('-')
            dayOfMonth()
            char(' ')
            hour()
            char(':')
            minute()
            char(':')
            second()
            char(' ')
            offsetHours()
            char(':')
            offsetMinutesOfHour()
        }

        val zone = TimeZone.of("Europe/Berlin")
        val instant = Instant.parse("2023-06-15T10:30:00Z")

        // This should work when offset is properly set
        val result = readableFormat.format {
            setDateTime(instant.toLocalDateTime(zone))
            setOffset(zone.offsetAt(instant))
        }

        assertEquals("2023-06-15 12:30:00 +02:00", result)
    }
}
"}

